class Solution:
    def maximumScore(self, nums):
        n = len(nums)
        best = None
        for i in range(n - 1):
            prefix = sum(nums[:i + 1])
            suffix_min = min(nums[i + 1:])
            score = prefix - suffix_min
            if best is None or score > best:
                best = score
        return best

