class Solution:
    def maximumScore(self, nums):
        n = len(nums)
        suffix_min = [0] * n
        suffix_min[n - 1] = nums[n - 1]
        for i in range(n - 2, -1, -1):
            suffix_min[i] = min(suffix_min[i + 1], nums[i])
        best = None
        prefix = 0
        for i in range(n - 1):
            prefix += nums[i]
            score = prefix - suffix_min[i + 1]
            if best is None or score > best:
                best = score
        return best

