var maximumScore = function(nums) {
    const n = nums.length;
    const suffixMin = new Array(n);
    suffixMin[n - 1] = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        suffixMin[i] = Math.min(suffixMin[i + 1], nums[i]);
    }
    let best = null;
    let prefix = 0;
    for (let i = 0; i < n - 1; i++) {
        prefix += nums[i];
        const score = prefix - suffixMin[i + 1];
        if (best === null || score > best) {
            best = score;
        }
    }
    return best;
};
